#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <fcntl.h>
#include <errno.h>

/* == EXEMPLE =======================================
 * O_NONBLOCK sur un pipe : write quand buffer plein
 * Montre que write non-bloquant retourne EAGAIN si
 * le buffer kernel est plein.
 * ================================================= */
void example_nonblock_write(void) {
    int fd[2];
    pipe(fd);
    fcntl(fd[1], F_SETFL, O_NONBLOCK);
    char data[1024];
    memset(data, 'A', sizeof(data));
    int count = 0;
    while (write(fd[1], data, sizeof(data)) > 0) count++;
    printf("Wrote %d KB before EAGAIN\n", count);
    close(fd[0]); close(fd[1]);
}
/* Resultat: Wrote N KB before EAGAIN */

/* == VOTRE EXERCICE ================================
 * O_NONBLOCK en lecture : read sur pipe vide → EAGAIN
 * Puis write + read avec succes.
 * ================================================= */
